static int em_check_format_string(const char *val) {
    if (val == NULL || val[0] == '\0')
        return 0;
    /* Detect format string specifiers: %s, %x, %n, %p, %d */
    const char *p = val;
    while (*p) {
        if (*p == '%') {
            char next = *(p + 1);
            if (next == 's' || next == 'x' || next == 'n' ||
                next == 'p' || next == 'd' || next == '0' ||
                next == '.' || next == '-')
                return 1;
        }
        p++;
    }
    return 0;
}
